/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(SalesEditLines, BillOfLadingDetails_ETGDeliveryOrderNo), FormControlEventType::Modified)]
public static void BillOfLadingDetails_ETGDeliveryOrderNo_OnModified(FormControl sender, FormControlEventArgs e)
{
    FormRun fr = sender.formRun();

    FormControl packing = fr.design().controlName("PrintFormLetter");

    FormDataSource billOfLadingDetails_DS = fr.dataSource(formDataSourceStr(SalesEditLines, ETG_BillOfLading)) as FormDataSource;
    ETG_BillOfLading billOfLading = billOfLadingDetails_DS.cursor();

    ETG_BillOfLading billOfLadingOrg;

    select * from billOfLadingOrg where billOfLadingOrg.ETGDeliveryOrderNo == billOfLading.ETGDeliveryOrderNo;

    if(billOfLadingOrg)
    {
        throw error(strFmt("Delivery order number - %1 is already exists. Please specify unique", billOfLadingOrg.ETGDeliveryOrderNo));
    }

}

/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormDataSourceEventHandler(formDataSourceStr(SalesEditLines, ETG_BillOfLading), FormDataSourceEventType::Activated)]
public static void ETG_BillOfLading_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    FormRun fr = sender.formRun();

    FormControl packing = fr.design().controlName("PrintFormLetter");
    FormControl deliveryOrderNo = fr.design().controlName("BillOfLadingDetails_ETGDeliveryOrderNo");
    FormDataSource billOfLading_DS = fr.dataSource(formDataSourceStr(SalesEditLines, ETG_BillOfLading)) as FormDataSource;

    ETG_BillOfLading billOfLading = billOfLading_DS.cursor();
    SalesLine salesLine;

    select * from salesLine where salesLine.SalesId == billOfLading.SalesId;

    if(salesLine.TaxGroup)
    {
        if(packing.labelText() == "Print packing slip")
        {
            deliveryOrderNo.visible(true);
        }
        else
        {
            deliveryOrderNo.visible(false);
        }
    }
}
